arguments.argument:
if global.gameProgress>=progCheck
{
  with oSwitchPanelColor
    instance_destroy()
  with oBarrierColor
    instance_destroy()
  with oKeyColor
    instance_destroy()
  with oLockPanelColor
    instance_destroy()
  with oEventBarrier
  {
    if spriteUse=1 {instance_destroy()}
  }
  instance_destroy()
}
